/*!id: jdt.internal.nameenvironment.findtype.remove-modules-chararrarr*/
/*!description: Updates internal JDT NameEnvironmentWithProgress.super.findType method call to remove the IModule[] modules argument as part of Java 9+ module system support evolution.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
super.findType($compoundName, $modules) :: sourceVersionGE(9)
=> super.findType($compoundName)
;;

/*!id: jdt.internal.nameenvironment.ispackage.remove-modules*/
/*!description: Updates internal JDT NameEnvironmentWithProgress.super.isPackage method call to remove the IModule[] modules argument as part of Java 9+ module system support evolution.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
super.isPackage($compoundName, $packageName, $modules) :: sourceVersionGE(9)
=> super.isPackage($compoundName, $packageName)
;;

/*!id: jdt.internal.packagebinding.findtype.remove-nullmodules*/
/*!description: Updates internal JDT PackageBinding.nameEnvironment.findType call to remove the explicit null for the modules argument, reflecting internal API change.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
nameEnvironment.findType(org.eclipse.jdt.internal.compiler.lookup.TypeConstants.PACKAGE_INFO_NAME, this.binding.compoundName, null) :: sourceVersionGE(9)
=> nameEnvironment.findType(org.eclipse.jdt.internal.compiler.lookup.TypeConstants.PACKAGE_INFO_NAME, this.binding.compoundName)
;;

/*!id: jdt.internal.ast.jls9.to.jls9internal*/
/*!description: Replaces AST.JLS9 with AST.JLS9_INTERNAL, an internal synonym, to prepare for future deprecation of JLS9 constant within JDT's internal API.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.core.dom.AST.JLS9
=> org.eclipse.jdt.core.dom.AST.JLS9_INTERNAL
;;
